                                {employerView === 'account' && <div className="p-4"><button onClick={()=>setAuth(false)} className="w-full p-4 bg-white rounded-xl shadow text-red-500">Çıkış</button></div>}
                            </main>
                            {employerView !== 'post-job' && <EmployerBottomNav currentView={employerView} setCurrentView={setEmployerView}/>}
                        </>
                    );
                }
            };

            return (
                <div className="bg-gray-100 min-h-screen flex items-center justify-center font-inter">
                    <div className={`relative w-full max-w-sm h-[850px] max-h-[100vh] bg-white sm:rounded-3xl shadow-2xl overflow-hidden flex flex-col ${mode === 'employer' ? 'employer-mode' : ''}`}>
                        {renderContent()}
                    </div>
                    {auth && <ModeSwitcher currentMode={mode} onToggle={()=>setMode(m => m==='worker'?'employer':'worker')}/>}
                </div>
            );
        };

        const root = ReactDOM.createRoot(document.getElementById('root'));
        root.render(<App />);
    </script>
</body>
</html>

