                             <button onClick={onNavigateToMap} className="flex-1 flex items-center justify-center space-x-2 py-3 bg-white border border-gray-200 rounded-xl font-semibold"><MapIcon className="w-5 h-5 text-gray-500"/><span>Harita</span></button>
                             <button className="flex-1 flex items-center justify-center space-x-2 py-3 bg-white border border-gray-200 rounded-xl font-semibold"><FilterIcon className="w-5 h-5 text-gray-500"/><span>Filtrele</span></button>
                         </div>
                         <div className="space-y-4">{jobs.map(job => <JobCard key={job.id} job={job} onViewJob={onViewJob} onApply={onViewJob} />)}</div>
                    </div>
                </div>
            );
        };

        const JobDetailsView = ({ job, onBack, onApply }) => {
            const [hasApplied, setHasApplied] = useState(false);
            const handleApplyClick = () => {
                if(!hasApplied) setHasApplied(true);
                else onApply(job);
            };

            return (
                <div className="relative bg-white h-full flex flex-col font-inter">
                    <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
                        <div className="relative h-80 w-full grayscale">
                            <img src={getJobImageForDetails(job.category)} className="absolute inset-0 w-full h-full object-cover"/>
                            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent opacity-90"/>
                            <div className="absolute top-0 left-0 right-0 p-4 flex justify-between items-center z-10">
                                <button onClick={onBack} className="p-2 bg-black/50 backdrop-blur-md rounded-full text-white"><ChevronLeftIcon className="w-6 h-6"/></button>
                            </div>
                            <div className="absolute bottom-10 left-6 right-6">
                                <h1 className="text-3xl font-black text-white leading-tight mb-2">{job.title}</h1>
                                <div className="flex items-center space-x-3">
                                    <img src={job.employerAvatarUrl} className="w-8 h-8 rounded-full border border-white/50 grayscale"/>
                                    <span className="text-white font-medium text-sm">{job.employer}</span>
                                </div>
                            </div>
                        </div>
                        <div className="px-6 py-8">
                            <div className="flex items-end justify-between mb-8 border-b border-gray-100 pb-6">
                                <div><p className="text-xs text-gray-400 font-bold uppercase mb-1">Ücret</p><span className="text-4xl font-black text-black tracking-tighter">{job.payRate}</span></div>
                                {hasApplied ? <div className="px-3 py-1 bg-black text-white text-xs font-bold rounded-full flex items-center"><CheckCircleIcon className="w-3.5 h-3.5 mr-1"/>BAŞVURULDU</div> : job.isUrgent && <div className="px-3 py-1 border border-black text-black text-xs font-bold rounded-full flex items-center"><ClockIcon className="w-3.5 h-3.5 mr-1"/>ACİL İLAN</div>}
                            </div>
                            <div className="grid grid-cols-2 gap-4 mb-8">
                                <div className="p-4 border border-gray-200 rounded-xl"><p className="text-xs text-gray-400 font-bold uppercase">Tarih</p><p className="font-bold">{job.date}</p></div>
                                <div className="p-4 border border-gray-200 rounded-xl"><p className="text-xs text-gray-400 font-bold uppercase">Saat</p><p className="font-bold">{job.shiftTime}</p></div>
                                <div className="col-span-2 p-4 border border-gray-200 rounded-xl flex justify-between items-center"><div><p className="text-xs text-gray-400 font-bold uppercase">Konum</p><p className="font-bold">{job.location.address}</p></div><span className="text-xs font-semibold bg-gray-100 px-2 py-1 rounded">{job.distance} km</span></div>
                            </div>
                            <div className="mb-8"><h3 className="font-bold text-lg mb-3">İş Tanımı</h3><p className="text-gray-600 text-sm leading-7">{job.description}</p></div>
                        </div>
                    </div>
                    <div className="absolute bottom-0 left-0 right-0 z-30 border-t border-gray-200 bg-white">
                        <button onClick={handleApplyClick} className={`w-full py-4 font-bold text-lg rounded-none flex items-center justify-center space-x-2 ${hasApplied ? 'bg-black text-white' : 'bg-[#39FF14] text-black'}`}>
                            {hasApplied ? <><MessageSquareIcon className="w-5 h-5"/><span>Mesaj At</span></> : <><span>Hemen Başvur</span><ChevronRightIcon className="w-5 h-5"/></>}
                        </button>
                    </div>
                </div>
            );
        };

        const MessagesView = ({ conversations, onSelectConversation }) => (
            <div className="flex flex-col h-full bg-gray-100">
                <header className="p-4 bg-white sticky top-0 z-10 shadow-sm"><h1 className="text-2xl font-bold text-gray-900">Mesajlar</h1></header>
                <main className="flex-grow overflow-y-auto no-scrollbar p-3 space-y-3">
                    {conversations.map(c => (
                        <button key={c.id} onClick={() => onSelectConversation(c)} className="w-full flex items-start space-x-4 p-4 bg-white rounded-xl shadow-sm border border-gray-100 text-left">
                            <img src={c.employerAvatarUrl} className="w-14 h-14 rounded-full object-cover"/>
                            <div className="flex-1 min-w-0">
                                <div className="flex justify-between"><h3 className="font-bold text-gray-800 truncate">{c.employer}</h3><span className="text-xs text-gray-400">{c.lastMessageTime}</span></div>
                                <p className="text-sm text-gray-500 truncate mt-1">{c.lastMessage}</p>
                            </div>
                        </button>
                    ))}
                </main>
            </div>
        );

        const ChatPage = ({ job, onBack, userMode }) => {
             const [msg, setMsg] = useState('');
             const [messages, setMessages] = useState([{id:1, text:'Merhaba', sender: userMode === 'worker' ? 'employer' : 'worker'}]);
             return (
                 <div className="flex flex-col h-full bg-gray-100">
                    <header className="bg-white px-4 py-3 border-b border-gray-200 flex items-center gap-3">
                        <button onClick={onBack}><ChevronLeftIcon className="w-6 h-6"/></button>
                        <h3 className="font-bold text-gray-900">{userMode === 'worker' ? job.employer : job.applicantName}</h3>
                    </header>
                    <main className="flex-1 p-4 overflow-y-auto space-y-4">
                        {messages.map(m => (
                            <div key={m.id} className={`flex ${m.sender === (userMode === 'worker' ? 'user' : 'employer') ? 'justify-end' : 'justify-start'}`}>
                                <div className={`px-4 py-2 rounded-2xl ${m.sender === (userMode === 'worker' ? 'user' : 'employer') ? 'bg-[#39FF14]' : 'bg-white border'}`}>{m.text}</div>
                            </div>
                        ))}
                    </main>
                    <footer className="p-3 bg-white border-t flex gap-2">
                        <input value={msg} onChange={e=>setMsg(e.target.value)} className="flex-1 bg-gray-100 rounded-full px-4 outline-none" placeholder="Mesaj yaz..."/>
                        <button onClick={()=>{setMessages([...messages, {id:Date.now(), text:msg, sender: userMode === 'worker' ? 'user' : 'employer'}]); setMsg('')}} className="p-3 bg-[#39FF14] rounded-full"><SendIcon className="w-5 h-5"/></button>
                    </footer>
                 </div>
             );
        };

        const WalletView = ({ balance, onBack, userMode, transactions, onTransaction }) => {
            const [modal, setModal] = useState(null);
            const [amount, setAmount] = useState('');
            return (
                <div className="flex flex-col h-full bg-gray-50 relative">
                     <header className="flex items-center p-4 bg-white sticky top-0 z-10 border-b border-gray-100"><button onClick={onBack}><ChevronLeftIcon className="w-6 h-6"/></button><h1 className="text-xl font-bold ml-2">Cüzdanım</h1></header>
                     <main className="flex-1 overflow-y-auto no-scrollbar p-4 space-y-6">
                        <div className={`p-6 rounded-2xl shadow-lg text-white ${userMode === 'employer' ? 'bg-gray-800' : 'bg-gray-900'}`}>
                            <p className="text-sm text-gray-300">Bakiye</p><p className="text-4xl font-bold mt-1">₺{balance}</p>
                            <div className="mt-4 flex space-x-3">
                                {userMode === 'employer' ? <button onClick={()=>setModal('deposit')} className="flex items-center bg-[#39FF14] text-black px-4 py-2 rounded-lg font-bold text-sm"><PlusCircleIcon className="w-4 h-4 mr-2"/>Yükle</button>
                                : <button onClick={()=>setModal('withdraw')} className="flex items-center bg-white/20 px-4 py-2 rounded-lg font-bold text-sm backdrop-blur"><MinusCircleIcon className="w-4 h-4 mr-2"/>Çek</button>}
                            </div>
                        </div>
                        <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                             <h3 className="font-bold text-lg mb-2">İşlem Geçmişi</h3>
                             {transactions.map(t => (
                                 <div key={t.id} className="flex justify-between py-3 border-b last:border-0 border-gray-100">
                                     <div><p className="font-semibold">{t.title}</p><p className="text-xs text-gray-500">{t.date}</p></div>
                                     <p className={`font-bold ${t.amount > 0 ? 'text-green-600' : 'text-red-600'}`}>₺{Math.abs(t.amount)}</p>
                                 </div>
                             ))}
                        </div>
                     </main>
                     {modal && (
                         <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
                             <div className="bg-white w-full max-w-sm rounded-3xl p-6">
                                 <h3 className="text-xl font-bold mb-4">{modal === 'deposit' ? 'Bakiye Yükle' : 'Para Çek'}</h3>
                                 <input type="number" value={amount} onChange={e=>setAmount(e.target.value)} className="w-full bg-gray-50 border-2 rounded-xl py-3 px-4 text-xl font-bold mb-4" placeholder="0.00"/>
                                 <div className="flex gap-3">
                                     <button onClick={()=>setModal(null)} className="flex-1 py-3 bg-gray-200 font-bold rounded-xl">İptal</button>
                                     <button onClick={()=>{onTransaction(parseFloat(amount), modal); setModal(null);}} className="flex-1 py-3 bg-black text-white font-bold rounded-xl">Onayla</button>
                                 </div>
                             </div>
                         </div>
                     )}
                </div>
            );
        };

        const ProfileView = ({ user, onLogout, onNavigate, onOpenQrPopup, trustScore }) => (
            <div className="p-4 bg-gray-50 min-h-full space-y-6">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 relative">
                     <button onClick={onOpenQrPopup} className="absolute top-4 right-4 p-2 bg-gray-100 rounded-full"><QrCodeIcon className="w-5 h-5"/></button>
                     <div className="flex flex-col items-center">
                         <img src={user.avatarUrl} className="w-28 h-28 rounded-full border-4 border-white shadow-lg"/>
                         <h1 className="text-3xl font-bold text-gray-900 mt-4">{user.name}</h1>
                     </div>
                     <div className="mt-5 pt-4 border-t border-gray-100">
                         <div className="flex justify-between items-center mb-2"><span className="font-semibold text-gray-800">Güven Puanı</span><span className="font-bold">{trustScore}%</span></div>
                         <div className="w-full bg-gray-200 rounded-full h-2"><div className="bg-[#39FF14] h-2 rounded-full" style={{width: `${trustScore}%`}}/></div>
                     </div>
                </div>
                <div className="space-y-3">
                    <button onClick={()=>onNavigate('edit-profile')} className="w-full p-4 bg-white rounded-xl shadow-sm border border-gray-100 text-left font-semibold flex justify-between"><span>Profilimi Düzenle</span><ChevronRightIcon className="w-5 h-5 text-gray-400"/></button>
                    <button onClick={()=>onNavigate('wallet')} className="w-full p-4 bg-white rounded-xl shadow-sm border border-gray-100 text-left font-semibold flex justify-between"><span>Mesai Cüzdanım</span><ChevronRightIcon className="w-5 h-5 text-gray-400"/></button>
                    <button onClick={()=>onNavigate('security')} className="w-full p-4 bg-white rounded-xl shadow-sm border border-gray-100 text-left font-semibold flex justify-between"><span>Güvenlik ve Doğrulama</span><ChevronRightIcon className="w-5 h-5 text-gray-400"/></button>
                    <button onClick={onLogout} className="w-full p-4 bg-white rounded-xl shadow-sm border border-gray-100 text-left font-semibold text-red-500 flex justify-between"><span>Çıkış Yap</span><LogOutIcon className="w-5 h-5"/></button>
                </div>
            </div>
        );

        // --- EMPLOYER VIEWS ---

        const EmployerDashboardView = ({ user, postedJobs, onSelectJob, onPostNewJob }) => {
            const activeCount = postedJobs.filter(j=>j.status === 'active').length;
            const appCount = postedJobs.reduce((acc,j) => acc + (j.applicantCount||0), 0);
            const compCount = postedJobs.filter(j=>j.status === 'completed').length;

            return (
                <div className="flex flex-col h-full bg-[#F7F8FC]">
                    <header className="p-4 bg-white sticky top-0 z-10 border-b border-gray-200 flex justify-between items-center">
                        <div><p className="text-sm text-gray-500">Hoş Geldin,</p><h1 className="text-2xl font-bold">{user.name}</h1></div>
                        <button className="p-2 bg-gray-100 rounded-full"><BellIcon className="w-6 h-6"/></button>
                    </header>
                    <main className="flex-1 overflow-y-auto no-scrollbar p-4 space-y-6">
                        <div className="grid grid-cols-3 gap-2">
                             <StatCard label="Aktif İlan" value={activeCount} icon="briefcase" color="green"/>
                             <StatCard label="Başvurular" value={appCount} icon="users" color="blue"/>
                             <StatCard label="Tamamlanan" value={compCount} icon="check" color="purple"/>
                        </div>
                        {postedJobs.filter(j=>j.status==='active').map(job => <JobPostingCard key={job.id} job={job} onSelect={()=>onSelectJob(job)}/>)}
                    </main>
                </div>
            );
        };

        const PostJobView = ({ onBack, onPostJob }) => {
            const [step, setStep] = useState(1);
            const [details, setDetails] = useState({ title: '', category: '', payRate: '', description: '', location: 'Mevcut Konum' });

            const handlePost = () => onPostJob({ ...details, id: Date.now().toString(), status: 'active', date: 'Bugün' });

            return (
                <div className="flex flex-col h-full bg-[#F7F8FC] relative">
                    <header className="flex items-center p-4 bg-white border-b border-gray-200 sticky top-0 z-20"><button onClick={onBack}><ChevronLeftIcon className="w-6 h-6"/></button><h1 className="text-xl font-bold ml-2">Yeni İlan Oluştur</h1></header>
                    <main className="flex-1 overflow-y-auto no-scrollbar p-4 space-y-6 pb-40">
                         {step === 1 && (
                             <div className="bg-white p-4 rounded-2xl border border-gray-200 shadow-sm space-y-4">
                                <h2 className="font-bold text-lg">İş Detayları</h2>
                                <input value={details.title} onChange={e=>setDetails({...details, title:e.target.value})} placeholder="İlan Başlığı" className="w-full h-12 border-2 border-gray-100 rounded-lg px-4"/>
                                <input value={details.category} onChange={e=>setDetails({...details, category:e.target.value})} placeholder="Kategori" className="w-full h-12 border-2 border-gray-100 rounded-lg px-4"/>
                                <textarea value={details.description} onChange={e=>setDetails({...details, description:e.target.value})} placeholder="Açıklama" rows={4} className="w-full border-2 border-gray-100 rounded-lg p-4"/>
                             </div>
                         )}
                         {step === 2 && (
                             <div className="bg-white p-4 rounded-2xl border border-gray-200 shadow-sm space-y-4">
                                <h2 className="font-bold text-lg">Ödeme</h2>
                                <input type="number" value={details.payRate} onChange={e=>setDetails({...details, payRate:e.target.value})} placeholder="Ücret (TL)" className="w-full h-12 border-2 border-gray-100 rounded-lg px-4"/>
                             </div>
                         )}
                    </main>
                    <footer className="absolute bottom-0 left-0 right-0 p-4 bg-white/90 backdrop-blur-sm border-t border-gray-200 flex gap-4 z-30">
                        {step > 1 && <button onClick={()=>setStep(s=>s-1)} className="flex-1 py-3 bg-gray-100 font-bold rounded-xl">Geri</button>}
                        {step < 2 ? <button onClick={()=>setStep(s=>s+1)} className="flex-[2] py-3 bg-black text-white font-bold rounded-xl">İleri</button>
                        : <button onClick={handlePost} className="flex-[2] py-3 bg-[#39FF14] text-black font-bold rounded-xl">Yayınla</button>}
                    </footer>
                </div>
            );
        };

        const ApplicantsView = ({ job, applicants, onBack, onViewProfile, onHire, onReject }) => (
            <div className="flex flex-col h-full bg-[#F7F8FC]">
                 <header className="flex items-center p-4 bg-white border-b border-gray-200 sticky top-0 z-10"><button onClick={onBack}><ChevronLeftIcon className="w-6 h-6"/></button><div className="ml-2"><h1 className="text-xl font-bold truncate">{job.title}</h1><p className="text-sm text-gray-500">{applicants.length} Başvuru</p></div></header>
                 <main className="flex-1 overflow-y-auto p-4 space-y-3">
                     {applicants.map(app => <ApplicantCard key={app.id} applicant={app} onViewProfile={()=>onViewProfile(app)} onHire={()=>onHire(app)} onReject={()=>onReject(app)} onMessage={()=>{}}/>)}
                 </main>
            </div>
        );

        const PublicProfileView = ({ user, onBack, isEmployerView, onHire, onReject }) => (
            <div className="flex flex-col h-full bg-gray-50 overflow-y-auto">
                 <header className="flex items-center p-4 bg-white sticky top-0 border-b border-gray-100"><button onClick={onBack}><ChevronLeftIcon className="w-6 h-6"/></button><h1 className="text-xl font-bold ml-2">Aday Profili</h1></header>
                 <div className="p-4 space-y-6 pb-24">
                     <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center text-center">
                         <img src={user.avatarUrl} className="w-28 h-28 rounded-full border-4 border-white shadow-lg mb-4"/>
                         <h2 className="text-2xl font-bold">{user.name}</h2>
                         <p className="text-[#39FF14] font-bold">Güven Puanı: {user.trustScore}%</p>
                     </div>
                     <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100"><h3 className="font-bold text-lg mb-2">Beceriler</h3><div className="flex flex-wrap gap-2">{user.skills?.map(s=><span key={s} className="bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-sm font-medium">{s}</span>)}</div></div>
                 </div>
                 {isEmployerView && <div className="fixed bottom-0 left-0 right-0 p-4 bg-white border-t border-gray-100 flex gap-3 max-w-sm mx-auto">
                     <button onClick={onReject} className="flex-1 py-4 bg-red-50 text-red-600 font-bold rounded-2xl">Reddet</button>
                     <button onClick={onHire} className="flex-[1.5] py-4 bg-[#39FF14] text-black font-bold rounded-2xl">İşe Al</button>
                 </div>}
            </div>
        );

        // --------------------------------------------------------
        // 6. ANA UYGULAMA (App)
        // --------------------------------------------------------

        const App = () => {
            const [showSplash, setShowSplash] = useState(true);
            const [showOnboarding, setShowOnboarding] = useState(false);
            const [auth, setAuth] = useState(false);
            const [mode, setMode] = useState('worker'); // worker | employer
            const [view, setView] = useState('home'); 
            const [employerView, setEmployerView] = useState('dashboard');

            // Worker State
            const [selectedJob, setSelectedJob] = useState(null);
            const [showNotif, setShowNotif] = useState(false);
            const [showQr, setShowQr] = useState(false);
            const [activeConversation, setActiveConversation] = useState(null);
            const [walletBalance, setWalletBalance] = useState(1250);
            const [workerTransactions, setWorkerTransactions] = useState(mockTransactions);

            // Employer State
            const [postedJobs, setPostedJobs] = useState(mockPostedJobs);
            const [selectedPostedJob, setSelectedPostedJob] = useState(null);
            const [selectedApplicant, setSelectedApplicant] = useState(null);
            const [employerBalance, setEmployerBalance] = useState(15000);
            const [employerTransactionsList, setEmployerTransactionsList] = useState(mockEmployerTransactions);

            const handleLogin = () => { setAuth(true); };

            const handleWorkerTransaction = (amt, type) => {
                if(type === 'withdraw') {
                    setWalletBalance(p => p - amt);
                    setWorkerTransactions([ {id:Date.now(), type:'payout', title:'Para Çekme', date:'Bugün', amount: -amt}, ...workerTransactions]);
                }
            };

            const handleEmployerTransaction = (amt, type) => {
                 if(type === 'deposit') {
                    setEmployerBalance(p => p + amt);
                    setEmployerTransactionsList([ {id:Date.now(), type:'deposit', title:'Yükleme', date:'Bugün', amount: amt}, ...employerTransactionsList]);
                 }
            };

            const handleHire = (applicant) => {
                alert(`${applicant.name} işe alındı!`);
                setEmployerView('dashboard');
            };

            const handlePostNewJob = (job) => {
                setPostedJobs([job, ...postedJobs]);
                setEmployerView('dashboard');
            };

            const renderInner = () => {
                if(showSplash) return <SplashScreen onComplete={()=>{setShowSplash(false);setShowOnboarding(true)}}/>;
                if(showOnboarding) return <Onboarding onComplete={()=>{setShowOnboarding(false)}}/>;
                if(!auth) return <LoginScreen onLoginSuccess={handleLogin} />;

                if(mode === 'worker') {
                    return (
                        <>
                            <main className="flex-grow overflow-y-auto pb-20 no-scrollbar">
                                {view === 'home' && <HomeView user={mockUser} jobs={mockJobs} onViewJob={(j)=>{setSelectedJob(j);setView('job-details')}} notifications={[]} onToggleNotifications={()=>setShowNotif(!showNotif)} onNavigateToMap={()=>{}}/>}
                                {view === 'job-details' && selectedJob && <JobDetailsView job={selectedJob} onBack={()=>setView('home')} onApply={(j)=>{setActiveConversation({employer:j.employer, employerAvatarUrl:j.employerAvatarUrl}); setView('messages-chat')}}/>}
                                {view === 'messages' && <MessagesView conversations={mockConversations} onSelectConversation={(c)=>{setActiveConversation(c);setView('messages-chat')}}/>}
                                {view === 'messages-chat' && activeConversation && <ChatPage userMode="worker" job={activeConversation} onBack={()=>setView('messages')}/>}
                                {view === 'profile' && <ProfileView user={mockUser} onLogout={()=>setAuth(false)} onNavigate={(v)=>{if(v==='wallet')setView('wallet');}} onOpenQrPopup={()=>setShowQr(true)} trustScore={80}/>}
                                {view === 'wallet' && <WalletView userMode="worker" balance={walletBalance} transactions={workerTransactions} onBack={()=>setView('profile')} onTransaction={handleWorkerTransaction}/>}
                            </main>
                            <BottomNav currentView={view} setCurrentView={setView}/>
                            <NotificationOverlay isOpen={showNotif} onClose={()=>setShowNotif(false)} notifications={[]} onNotificationClick={()=>{}}/>
                            <QRCodePopup isOpen={showQr} onClose={()=>setShowQr(false)} userAvatarUrl={mockUser.avatarUrl} userName={mockUser.name}/>
                        </>
                    );
                } else {
                    return (
                        <>
                            <main className={`flex-grow overflow-y-auto no-scrollbar ${employerView === 'post-job' ? 'pb-0' : 'pb-20'}`}>
                                {employerView === 'dashboard' && <EmployerDashboardView user={mockEmployerUser} postedJobs={postedJobs} onSelectJob={(j)=>{setSelectedPostedJob(j);setEmployerView('applicants')}} />}
                                {employerView === 'post-job' && <PostJobView onBack={()=>setEmployerView('dashboard')} onPostJob={handlePostNewJob}/>}
                                {employerView === 'applicants' && selectedPostedJob && <ApplicantsView job={selectedPostedJob} applicants={mockApplicants[selectedPostedJob.id]||[]} onBack={()=>setEmployerView('dashboard')} onViewProfile={(app)=>{setSelectedApplicant(app);setEmployerView('applicant-profile')}} onHire={handleHire} onReject={()=>{alert('Reddedildi')}}/>}
                                {employerView === 'applicant-profile' && selectedApplicant && <PublicProfileView user={selectedApplicant} onBack={()=>setEmployerView('applicants')} isEmployerView={true} onHire={()=>handleHire(selectedApplicant)} onReject={()=>{alert('Reddedildi')}}/>}
                                {employerView === 'account' && <div className="p-4"><button onClick={()=>setEmployerView('wallet')} className="w-full p-4 bg-white rounded-xl shadow border mb-4 text-left font-bold">Cüzdanım</button><button onClick={()=>setAuth(false)} className="w-full p-4 bg-white rounded-xl shadow border text-left font-bold text-red-500">Çıkış</button></div>}
                                {employerView === 'wallet' && <WalletView userMode="employer" balance={employerBalance} transactions={employerTransactionsList} onBack={()=>setEmployerView('account')} onTransaction={handleEmployerTransaction}/>}
                                {employerView === 'messages' && <MessagesView conversations={Object.values(mockEmployerConversations).flat()} onSelectConversation={(c)=>{setActiveConversation(c);setEmployerView('chat')}}/>}
                                {employerView === 'chat' && <ChatPage userMode="employer" job={{...activeConversation, applicantName:activeConversation.applicantName}} onBack={()=>setEmployerView('messages')}/>}
                            </main>
                            {employerView !== 'post-job' && <EmployerBottomNav currentView={employerView} setCurrentView={setEmployerView}/>}
                        </>
                    )
                }
            };

            return (
                <div className="bg-gray-100 min-h-screen flex items-center justify-center font-inter">
                    <div className={`relative w-full max-w-sm h-[850px] max-h-[100vh] bg-white sm:rounded-3xl shadow-2xl overflow-hidden flex flex-col ${mode === 'employer' ? 'employer-mode' : ''}`}>
                        {renderInner()}
                    </div>
                    {auth && <ModeSwitcher currentMode={mode} onToggle={()=>setMode(m => m==='worker'?'employer':'worker')}/>}
                </div>
            );
        };

        const root = ReactDOM.createRoot(document.getElementById('root'));
        root.render(<App />);
    </script>
</body>
</html>

