} from '../components/Icons';
import { ProfileMenuItem } from '../components/ProfileMenuItem';

interface ProfileViewProps {
  user: User | null;
  onLogout: () => void;
  onNavigateToSubView: (view: 'security-verification' | 'edit-profile' | 'settings' | 'wallet') => void;
